const WebSocket = require('ws');
const http = require('http');

// Create an HTTP server
const server = http.createServer();

// Create a WebSocket server
const wss = new WebSocket.Server({ server });

// In-memory store for player data (for demonstration purposes)
const players = {};

// Function to validate and process commands
function processCommand(playerId, command) {
  // Example validation: ensure the command is one of 'build', 'attack', or 'move'
  if (!['build', 'attack', 'move'].includes(command.type)) {
    return { success: false, message: 'Invalid command type' };
  }

  // Process the command (this would typically involve game logic)
  console.log(`Player ${playerId} executed command:`, command);

  return { success: true, message: 'Command processed successfully' };
}

// Handle WebSocket connection
wss.on('connection', (ws) => {
  ws.on('message', (message) => {
    try {
      const data = JSON.parse(message);
      if (!data.playerId || !data.command) {
        return ws.send(JSON.stringify({ success: false, message: 'Invalid message format' }));
      }

      const playerId = data.playerId;
      const command = data.command;

      // Validate and process the command
      const result = processCommand(playerId, command);

      // Send response back to the client
      ws.send(JSON.stringify(result));
    } catch (error) {
      console.error('Error processing message:', error);
      ws.send(JSON.stringify({ success: false, message: 'Internal server error' }));
    }
  });

  ws.on('close', () => {
    delete players[playerId];
    console.log(`Player ${playerId} disconnected`);
  });
});

// Start the HTTP server
const PORT = process.env.PORT || 3000;
server.listen(PORT, () => {
  console.log(`WebSocket server is running on port ${PORT}`);
});